CREATE TABLE students (
  student_id  INT PRIMARY KEY,
  first_name  VARCHAR(50) NOT NULL,
  last_name   VARCHAR(50) NOT NULL,
  email       VARCHAR(80) UNIQUE,
  gpa         DECIMAL(3,2) DEFAULT 0.00
);

-- 1. Single-row INSERT with all columns in order
INSERT INTO students VALUES (1, 'Alice', 'Smith', 'alice@school.edu', 3.85);

-- 2. Single-row INSERT specifying column names (preferred style)
INSERT INTO students (student_id, first_name, last_name, email)
VALUES (2, 'Bob', 'Jones', 'bob@school.edu');  -- gpa uses DEFAULT

-- 3. Multi-row INSERT (one statement, multiple value tuples)
INSERT INTO students VALUES
  (3, 'Carol', 'Williams', 'carol@school.edu', 3.60),
  (4, 'Dave',  'Brown',    'dave@school.edu',  3.10),
  (5, 'Eve',   'Davis',    'eve@school.edu',   3.90);

SELECT * FROM students ORDER BY gpa DESC;

-- 4. INSERT ... SELECT: copy high-GPA students to an honours table
CREATE TABLE honours_students (
  student_id INT, name VARCHAR(100), gpa DECIMAL(3,2)
);

INSERT INTO honours_students (student_id, name, gpa)
SELECT student_id,
       first_name || ' ' || last_name AS name,
       gpa
FROM students
WHERE gpa >= 3.75;

SELECT * FROM honours_students;
